import React, { useEffect } from 'react';
import { useOrders } from '../../hooks/useOrders';

const OrderList: React.FC = () => {
    const { orders, fetchOrders, loading, error } = useOrders();

    useEffect(() => {
        fetchOrders();
    }, [fetchOrders]);

    if (loading) return <div>Loading...</div>;
    if (error) return <div>Error fetching orders: {error.message}</div>;

    return (
        <div>
            <h2>Order List</h2>
            <table>
                <thead>
                    <tr>
                        <th>Order ID</th>
                        <th>Customer Name</th>
                        <th>Status</th>
                        <th>Total</th>
                        <th>Actions</th>
                    </tr>
                </thead>
                <tbody>
                    {orders.map(order => (
                        <tr key={order.id}>
                            <td>{order.id}</td>
                            <td>{order.customerName}</td>
                            <td>{order.status}</td>
                            <td>{order.total}</td>
                            <td>
                                {/* Add action buttons for editing and deleting orders */}
                                <button>Edit</button>
                                <button>Delete</button>
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

export default OrderList;
